{"code": "import json

# Read the MIT packages result from file
result_file = locals()['var_functions.query_db:8']
with open(result_file, 'r') as f:
    mit_packages = json.load(f)

# Filter for packages with MIT license that are releases
release_mit_packages = []
for pkg in mit_packages:
    try:
        # Check if licenses contain MIT
        licenses = json.loads(pkg['Licenses'])
        if 'MIT' in licenses:
            # Check if it's a release
            version_info = json.loads(pkg['VersionInfo'])
            if version_info.get('IsRelease', False):
                release_mit_packages.append({
                    'System': pkg['System'],
                    'Name': pkg['Name'],
                    'Version': pkg['Version']
                })
    except:
        continue

print('__RESULT__:')
print(json.dumps({
    'count': len(release_mit_packages),
    'sample': release_mit_packages[:5]
}))"}

{"code": "import json
import re

# Read the MIT release packages from package_database
mit_packages_file = locals()['var_functions.query_db:8']
with open(mit_packages_file, 'r') as f:
    mit_packages = json.load(f)

# Filter for MIT license and release versions
mit_release_packages = []
for pkg in mit_packages:
    try:
        licenses = json.loads(pkg['Licenses'])
        if 'MIT' in licenses:
            version_info = json.loads(pkg['VersionInfo'])
            if version_info.get('IsRelease', False):
                mit_release_packages.append({
                    'System': pkg['System'],
                    'Name': pkg['Name'],
                    'Version': pkg['Version']
                })
    except:
        continue

# Read the project_packageversion mappings
proj_pkg_file = locals()['var_functions.query_db:14']
with open(proj_pkg_file, 'r') as f:
    project_mappings = json.load(f)

# Create a lookup dictionary for project mappings
# Key: (System, Name, Version) -> ProjectName
project_lookup = {}
for mapping in project_mappings:
    key = (mapping['System'], mapping['Name'], mapping['Version'])
    project_lookup[key] = mapping['ProjectName']

# Find matching projects for our MIT release packages
matched_projects = []
for pkg in mit_release_packages:
    key = (pkg['System'], pkg['Name'], pkg['Version'])
    if key in project_lookup:
        matched_projects.append({
            'System': pkg['System'],
            'Name': pkg['Name'],
            'Version': pkg['Version'],
            'ProjectName': project_lookup[key]
        })

print('__RESULT__:')
print(json.dumps({
    'total_mit_release_packages': len(mit_release_packages),
    'matched_projects': len(matched_projects),
    'sample_matches': matched_projects[:5]
}))"}

